import{_ as i,o as l,c as e,ag as r}from"./chunks/framework.BuUvxvtQ.js";const u=JSON.parse('{"title":"Безопасность аккаунта ВКонтакте","description":"","frontmatter":{},"headers":[],"relativePath":"vk-security.md","filePath":"vk-security.md"}'),t={name:"vk-security.md"};function o(d,a,s,c,h,n){return l(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="безопасность-аккаунта-вконтакте" tabindex="-1">Безопасность аккаунта ВКонтакте <a class="header-anchor" href="#безопасность-аккаунта-вконтакте" aria-label="Permalink to &quot;Безопасность аккаунта ВКонтакте&quot;">​</a></h1><p>ВКонтакте часто используется как основная социальная сеть для общения, подписок на сообщества, хранения медиа и авторизации в сторонних сервисах. Поэтому важно контролировать и доступ к профилю, и приватность опубликованных данных.</p><h2 id="практические-рекомендации" tabindex="-1">Практические рекомендации <a class="header-anchor" href="#практические-рекомендации" aria-label="Permalink to &quot;Практические рекомендации&quot;">​</a></h2><div class="card-grid"><div class="platform-card"><h3>Проверьте номер телефона и почту</h3><p>Убедитесь, что к аккаунту привязаны актуальные контакты, к которым есть доступ только у вас.</p></div><div class="platform-card"><h3>Смените слабый пароль</h3><p>Если пароль короткий или использовался в других сервисах, замените его на уникальный и длинный.</p></div><div class="platform-card"><h3>Включите подтверждение входа</h3><p>Активируйте дополнительные проверки входа, если они доступны, и сохраните резервные данные для восстановления.</p></div></div><h2 id="что-проверить-в-настроиках-вконтакте" tabindex="-1">Что проверить в настройках ВКонтакте <a class="header-anchor" href="#что-проверить-в-настроиках-вконтакте" aria-label="Permalink to &quot;Что проверить в настройках ВКонтакте&quot;">​</a></h2><ul><li>историю входов и активные устройства;</li><li>подключенные приложения и сайты;</li><li>видимость номера телефона, даты рождения, списка друзей и фотографий;</li><li>кто может писать вам сообщения и приглашать в сообщества;</li><li>уведомления о входе в аккаунт и изменении настроек безопасности.</li></ul><h2 id="как-снизить-риск-фишинга-во-вконтакте" tabindex="-1">Как снизить риск фишинга во ВКонтакте <a class="header-anchor" href="#как-снизить-риск-фишинга-во-вконтакте" aria-label="Permalink to &quot;Как снизить риск фишинга во ВКонтакте&quot;">​</a></h2><ul><li>не вводите пароль после перехода по ссылке из личных сообщений;</li><li>не отправляйте коды подтверждения даже знакомым;</li><li>не доверяйте сообщениям о «проверке страницы», если они пришли не через официальное приложение;</li><li>проверяйте, не открыта ли поддельная страница входа в браузере.</li></ul><h2 id="после-подозрительнои-активности" tabindex="-1">После подозрительной активности <a class="header-anchor" href="#после-подозрительнои-активности" aria-label="Permalink to &quot;После подозрительной активности&quot;">​</a></h2><ol><li>Сразу смените пароль.</li><li>Завершите все сеансы, кроме текущего доверенного устройства.</li><li>Проверьте подключенные приложения.</li><li>Убедитесь, что номер телефона и почта не были изменены.</li><li>Предупредите знакомых, если от вашего имени могли рассылаться странные сообщения.</li></ol><div class="screenshot-placeholder"> Здесь будет размещен актуальный скриншот настроек безопасности ВКонтакте: входы, устройства, подтверждение входа и приватность профиля. </div>',11)])])}const _=i(t,[["render",o]]);export{u as __pageData,_ as default};
